import React, { useState, useContext } from "react";
import { Link, useNavigate } from "react-router-dom";
import { CheckCircle, Eye, EyeOff, KeyRound, Mail, ShieldPlus, UserRound, Users } from "lucide-react";
import { motion } from "framer-motion";
import API from "../../api/api";
import { ToastContext } from "../../context/ToastContext";
import { TopLoaderContext } from "../../context/TopLoaderContext";

const STEPS = ["Create Profile", "Set Password", "Add Contacts"];

const PERKS = [
    { icon: CheckCircle, text: "Emergency profile" },
    { icon: Users, text: "Trusted contacts" },
    { icon: CheckCircle, text: "Live SOS alerts" },
];

export default function Register() {
    const navigate = useNavigate();
    const { addToast } = useContext(ToastContext);
    const { start: loaderStart, done: loaderDone } = useContext(TopLoaderContext);

    const [name, setName] = useState("");
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [confirmPassword, setConfirmPassword] = useState("");

    const [showPassword, setShowPassword] = useState(false);
    const [showConfirm, setShowConfirm] = useState(false);
    const [pwFocused, setPwFocused] = useState(false);

    /* ── Password strength scorer (shared with Profile page) ── */
    const getPwStrength = (pwd) => {
        if (!pwd) return null;
        let score = 0;
        if (pwd.length >= 8)  score++;
        if (pwd.length >= 12) score++;
        if (/[A-Z]/.test(pwd)) score++;
        if (/[0-9]/.test(pwd)) score++;
        if (/[^A-Za-z0-9]/.test(pwd)) score++;
        score = Math.min(score, 4);
        const levels = [
            { label: 'Weak',        color: '#ef4444' },
            { label: 'Fair',        color: '#f59e0b' },
            { label: 'Good',        color: '#06b6d4' },
            { label: 'Strong',      color: '#22c55e' },
            { label: 'Very Strong', color: '#16a34a' },
        ];
        return { score, ...levels[score] };
    };

    const handleSubmit = async (event) => {
        event.preventDefault();

        if (password !== confirmPassword) {
            addToast("❌ Passwords do not match", "error");
            return;
        }

        loaderStart();
        try {
            const res = await API.post("/auth/register", { name, email, password });
            // JWT is stored in an httpOnly cookie by the backend
            localStorage.setItem("safeher_logged_in", "1");
            if (res.data.name) localStorage.setItem("userName", res.data.name);
            localStorage.removeItem("userAvatar"); // fresh account — no avatar yet
            addToast("✅ Registration successful! Welcome to SafeHer.", "success");
            loaderDone();
            navigate("/");
        } catch (err) {
            loaderDone();
            addToast("❌ " + (err.response?.data?.msg || "Registration failed"), "error");
        }
    };

    return (
        <motion.section
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.48 }}
            className="mx-auto w-full max-w-2xl"
        >
            <div className="overflow-hidden rounded-3xl border border-slate-200 bg-white shadow-2xl dark:border-white/10 dark:bg-[#0d1628]">

                {/* ── Top gradient banner ── */}
                <div className="relative overflow-hidden bg-[#060d1f] px-8 py-8">
                    <div className="pointer-events-none absolute -right-16 -top-16 h-52 w-52 rounded-full bg-rose-500/25 blur-2xl" />
                    <div className="pointer-events-none absolute -bottom-10 left-0 h-44 w-64 rounded-full bg-fuchsia-500/20 blur-2xl" />
                    <div
                        className="pointer-events-none absolute inset-0 opacity-[0.04]"
                        style={{ backgroundImage: "linear-gradient(rgba(255,255,255,1) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,1) 1px,transparent 1px)", backgroundSize: "32px 32px" }}
                    />
                    <div className="relative flex flex-col items-center text-center">
                        <div className="grid h-14 w-14 place-items-center rounded-2xl bg-linear-to-br from-rose-400 to-fuchsia-600 shadow-lg shadow-rose-500/30">
                            <ShieldPlus className="h-7 w-7 text-white" />
                        </div>
                        <h1 className="mt-4 font-['Sora'] text-2xl font-bold text-white">Join SafeHer</h1>
                        <p className="mt-1.5 text-sm text-slate-400">Build your emergency identity and safety network.</p>

                        {/* Step indicators */}
                        <div className="mt-5 flex items-center gap-1.5">
                            {STEPS.map((step, i) => (
                                <div key={step} className="flex items-center">
                                    <div
                                        className={`flex items-center gap-1.5 rounded-full px-3 py-1 text-xs font-semibold ${i === 0
                                            ? "bg-rose-500/20 text-rose-300 ring-1 ring-rose-400/40"
                                            : "bg-white/5 text-slate-500"
                                            }`}
                                    >
                                        <span className={`h-1.5 w-1.5 rounded-full ${i === 0 ? "bg-rose-400" : "bg-slate-600"}`} />
                                        {step}
                                    </div>
                                    {i < STEPS.length - 1 && <div className="mx-1 h-px w-4 bg-white/10" />}
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                {/* ── Form body ── */}
                <div className="p-8">
                    <form className="space-y-4" onSubmit={handleSubmit}>
                        <div className="grid gap-4 sm:grid-cols-2">
                            <div>
                                <label className="mb-1.5 block text-xs font-semibold uppercase tracking-widest text-slate-500 dark:text-slate-400">Full Name</label>
                                <div className="flex items-center gap-2.5 rounded-xl border border-slate-300 bg-slate-50 px-3.5 transition focus-within:border-rose-400 focus-within:ring-2 focus-within:ring-rose-400/20 dark:border-white/10 dark:bg-white/5">
                                    <UserRound className="h-4 w-4 shrink-0 text-slate-400" />
                                    <input
                                        type="text"
                                        placeholder="Your full name"
                                        className="w-full bg-transparent py-3 text-sm text-slate-900 dark:text-white placeholder:text-slate-400 focus:outline-none"
                                        value={name}
                                        autoComplete="name"
                                        onChange={(e) => setName(e.target.value)}
                                        required
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="mb-1.5 block text-xs font-semibold uppercase tracking-widest text-slate-500 dark:text-slate-400">Email</label>
                                <div className="flex items-center gap-2.5 rounded-xl border border-slate-300 bg-slate-50 px-3.5 transition focus-within:border-rose-400 focus-within:ring-2 focus-within:ring-rose-400/20 dark:border-white/10 dark:bg-white/5">
                                    <Mail className="h-4 w-4 shrink-0 text-slate-400" />
                                    <input
                                        type="email"
                                        placeholder="you@example.com"
                                        className="w-full bg-transparent py-3 text-sm text-slate-900 dark:text-white placeholder:text-slate-400 focus:outline-none"
                                        value={email}
                                        autoComplete="email"
                                        onChange={(e) => setEmail(e.target.value)}
                                        required
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="grid gap-4 sm:grid-cols-2">
                            {/* Password field with strength popup */}
                            <div style={{ position: 'relative' }}>
                                <label className="mb-1.5 block text-xs font-semibold uppercase tracking-widest text-slate-500 dark:text-slate-400">Password</label>
                                <div className="flex items-center gap-2.5 rounded-xl border border-slate-300 bg-slate-50 px-3.5 transition focus-within:border-rose-400 focus-within:ring-2 focus-within:ring-rose-400/20 dark:border-white/10 dark:bg-white/5">
                                    <KeyRound className="h-4 w-4 shrink-0 text-slate-400" />
                                    <input
                                        type={showPassword ? "text" : "password"}
                                        placeholder="••••••••"
                                        className="w-full bg-transparent py-3 text-sm text-slate-900 dark:text-white placeholder:text-slate-400 focus:outline-none"
                                        value={password}
                                        autoComplete="new-password"
                                        onChange={(e) => setPassword(e.target.value)}
                                        onFocus={() => setPwFocused(true)}
                                        onBlur={() => setPwFocused(false)}
                                        required
                                        minLength="6"
                                    />
                                    <button
                                        type="button"
                                        onClick={() => setShowPassword((v) => !v)}
                                        className="rounded p-1 text-slate-400 transition hover:text-slate-600 dark:hover:text-slate-200"
                                        aria-label={showPassword ? "Hide password" : "Show password"}
                                    >
                                        {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                                    </button>
                                </div>
                                {/* Strength popup — only while focused */}
                                {password && pwFocused && (() => {
                                    const s = getPwStrength(password);
                                    if (!s) return null;
                                    const legend = [
                                        { label: 'Weak',        color: '#ef4444', emoji: '🔴' },
                                        { label: 'Fair',        color: '#f59e0b', emoji: '🟡' },
                                        { label: 'Good',        color: '#06b6d4', emoji: '🔵' },
                                        { label: 'Strong',      color: '#22c55e', emoji: '🟢' },
                                        { label: 'Very Strong', color: '#16a34a', emoji: '🟢' },
                                    ];
                                    return (
                                        <div className="pw-strength-popup">
                                            <div className="pw-strength-bar">
                                                {[0, 1, 2, 3].map(i => (
                                                    <div key={i} className="pw-strength-seg" style={{ background: i < s.score ? s.color : undefined }} />
                                                ))}
                                            </div>
                                            <p className="pw-strength-current" style={{ color: s.color }}>{s.label}</p>
                                            <table className="pw-strength-legend">
                                                <tbody>
                                                    {legend.map(row => (
                                                        <tr key={row.label} style={{ opacity: s.label === row.label ? 1 : 0.38 }}>
                                                            <td className="pw-legend-emoji">{row.emoji}</td>
                                                            <td className="pw-legend-label" style={{ color: s.label === row.label ? row.color : undefined, fontWeight: s.label === row.label ? 700 : 500 }}>{row.label}</td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>
                                    );
                                })()}
                            </div>
                            <div>
                                <label className="mb-1.5 block text-xs font-semibold uppercase tracking-widest text-slate-500 dark:text-slate-400">Confirm Password</label>
                                <div className="flex items-center gap-2.5 rounded-xl border border-slate-300 bg-slate-50 px-3.5 transition focus-within:border-rose-400 focus-within:ring-2 focus-within:ring-rose-400/20 dark:border-white/10 dark:bg-white/5">
                                    <KeyRound className="h-4 w-4 shrink-0 text-slate-400" />
                                    <input
                                        type={showConfirm ? "text" : "password"}
                                        placeholder="••••••••"
                                        className="w-full bg-transparent py-3 text-sm text-slate-900 dark:text-white placeholder:text-slate-400 focus:outline-none"
                                        value={confirmPassword}
                                        autoComplete="new-password"
                                        onChange={(e) => setConfirmPassword(e.target.value)}
                                        required
                                        minLength="6"
                                    />
                                    <button
                                        type="button"
                                        onClick={() => setShowConfirm((v) => !v)}
                                        className="rounded p-1 text-slate-400 transition hover:text-slate-600 dark:hover:text-slate-200"
                                        aria-label={showConfirm ? "Hide password" : "Show password"}
                                    >
                                        {showConfirm ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                                    </button>
                                </div>
                            </div>
                        </div>

                        {/* Perk highlights */}
                        <div className="grid grid-cols-3 gap-2 rounded-xl border border-slate-200 bg-slate-50 p-3 dark:border-white/10 dark:bg-white/5">
                            {PERKS.map(({ icon: Icon, text }) => (
                                <div key={text} className="flex items-center gap-1.5 text-xs text-slate-600 dark:text-slate-400">
                                    <Icon className="h-3.5 w-3.5 shrink-0 text-rose-400" />
                                    {text}
                                </div>
                            ))}
                        </div>

                        <button
                            type="submit"
                            style={{ background: "linear-gradient(to right, #fb7185, #a855f7)" }}
                            className="flex w-full items-center justify-center gap-2 rounded-xl py-3.5 text-sm font-bold text-white shadow-lg shadow-rose-500/20 transition hover:opacity-90 active:scale-[0.98]"
                        >
                            <ShieldPlus className="h-4 w-4" />
                            Create SafeHer Account
                        </button>
                    </form>

                    <p className="mt-5 text-center text-xs text-slate-600 dark:text-slate-400">
                        Already have an account?{" "}
                        <Link to="/login" className="font-semibold text-rose-500 hover:underline dark:text-rose-400">
                            Sign in →
                        </Link>
                    </p>
                </div>
            </div>
        </motion.section>
    );
}
